	@Test
	void unsupportedAlternativeRoutesRetainTopologyLocalLeaves() {
		Union opaqueLeft = new Union(pattern("left", "urn:test:left-a", "leftValue"),
				pattern("left", "urn:test:left-b", "leftValue"));
		StatementPattern writtenRight = pattern("right", "urn:test:right-written", "rightValue");
		Join root = new Join(opaqueLeft, writtenRight);
		Memo memo = memo();
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();
		int rightGroupId = rootExpression.inputs().get(1).groupId();
		RuleProof rewrite = new RuleProof("late-generic-rewrite", RuleKind.TRANSFORMATION,
				OptimizationGoal.BAG_SEMANTICS, Set.of("newLogicalShape"), "two alternative factor routes");
		memo.addLogicalAlternative(rightGroupId,
				new Join(pattern("right", "urn:test:right-a", "rightValue"),
						pattern("right", "urn:test:right-b", "rightValue")),
				List.of(rewrite)).orElseThrow();
		memo.addLogicalAlternative(rightGroupId,
				new Join(pattern("right", "urn:test:right-c", "rightValue"),
						pattern("right", "urn:test:right-d", "rightValue")),
				List.of(rewrite)).orElseThrow();

		List<MemoJoinRegionExtractor.Result> results = assertDoesNotThrow(
				() -> MemoJoinRegionExtractor.extractAlternatives(memo, rootGroupId, rootExpression,
						ignored -> true, ignored -> Optional.empty()));

		assertEquals(3, results.size(),
				"Unsupported routes with different local leaves must remain independently observable");
		assertTrue(results.stream().noneMatch(MemoJoinRegionExtractor.Result::supported));
		assertEquals(3, results.stream().map(MemoJoinRegionExtractor.Result::leafGroupIds).distinct().count());
	}

