	@Test
	void retainsScopeChangingJoinInputAsOrderedWholeFactor() throws ReflectiveOperationException {
		StatementPattern beforeA = pattern("beforeA", "urn:test:before-a", "beforeAValue");
		StatementPattern beforeB = pattern("beforeB", "urn:test:before-b", "beforeBValue");
		Join scoped = new Join(pattern("scopedA", "urn:test:scoped-a", "scopedAValue"),
				pattern("scopedB", "urn:test:scoped-b", "scopedBValue"));
		scoped.setVariableScopeChange(true);
		StatementPattern afterA = pattern("afterA", "urn:test:after-a", "afterAValue");
		StatementPattern afterB = pattern("afterB", "urn:test:after-b", "afterBValue");
		Join root = new Join(new Join(new Join(beforeA, beforeB), scoped), new Join(afterA, afterB));
		Memo memo = memo();
		int rootGroupId = memo.intern(root);
		int scopedGroupId = memo.intern(scoped.clone());

		Object extraction = extract(memo, rootGroupId, memo.group(rootGroupId).expressions().getFirst());

		assertTrue((boolean) invoke(extraction, "supported"),
				"A semantic barrier inside an ordinary inner join must delimit reordering, not disable it");
		JoinRegion region = (JoinRegion) invoke(extraction, "region");
		assertEquals(5, region.factors().size(), "The scoped join must remain one factor with two memo children");
		int scopedOccurrenceId = occurrenceId(region, scopedGroupId);
		Set<Integer> beforeOccurrenceIds = Set.of(occurrenceId(region, memo.intern(beforeA.clone())),
				occurrenceId(region, memo.intern(beforeB.clone())));
		Set<Integer> afterOccurrenceIds = Set.of(occurrenceId(region, memo.intern(afterA.clone())),
				occurrenceId(region, memo.intern(afterB.clone())));
		assertEquals(beforeOccurrenceIds, region.requiredBefore(scopedOccurrenceId),
				"The scope barrier must remain after every preceding factor");
		assertTrue(afterOccurrenceIds.stream()
				.allMatch(occurrenceId -> region.requiredBefore(occurrenceId).contains(scopedOccurrenceId)),
				"Every following factor must remain after the scope barrier");
		MemoExpr scopedExpression = memo.group(scopedGroupId)
				.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.filter(expression -> expression.tupleExpr() instanceof Join)
				.findFirst()
				.orElseThrow();
		assertEquals(2, scopedExpression.inputGroupIds().size(),
				"The whole factor must remain transparent to optimization of its own children");
		assertTrue(scopedExpression.inputs().stream().allMatch(input -> input.semanticBarrier()),
				"The child slots retain the scope boundary that prevents flattening");
	}

