	@Test
	void opaqueOuterRestrictionRetainsOrderedWholeFactor() {
		StatementPattern before = pattern("before", "urn:test:before", "beforeValue");
		Difference difference = new Difference(
				pattern("shared", "urn:test:included", "includedValue"),
				pattern("shared", "urn:test:excluded", "excludedValue"));
		StatementPattern after = pattern("after", "urn:test:after", "afterValue");
		Join root = new Join(new Join(before, difference), after);
		Memo memo = memo();
		int rootGroupId = memo.intern(root);
		int beforeGroupId = memo.intern(before.clone());
		int differenceGroupId = memo.intern(difference.clone());
		int afterGroupId = memo.intern(after.clone());
		OpaqueJoinFactorPolicy policy = expression -> {
			if (!(expression.tupleExpr() instanceof Difference)) {
				return Optional.empty();
			}
			var shape = memo.group(expression.groupId()).bindingShape();
			Set<OpaqueFactorDescriptor.SemanticBarrier> barriers = Set
					.of(OpaqueFactorDescriptor.SemanticBarrier.DIFFERENCE);
			return Optional.of(new OpaqueFactorDescriptor(
					memo.universe().names(shape.possible()), memo.universe().names(shape.assured()), Set.of(), Set.of(),
					barriers, barriers));
		};

		MemoJoinRegionExtractor.Result extraction = MemoJoinRegionExtractor.extract(memo, rootGroupId,
				memo.group(rootGroupId).expressions().getFirst(), policy);

		assertTrue(extraction.supported(), extraction.boundaries()::toString);
		JoinRegion region = extraction.region();
		assertEquals(3, region.factors().size(), "Difference must remain one factor with two memo children");
		int beforeOccurrenceId = occurrenceId(region, beforeGroupId);
		int differenceOccurrenceId = occurrenceId(region, differenceGroupId);
		int afterOccurrenceId = occurrenceId(region, afterGroupId);
		assertEquals(Set.of(beforeOccurrenceId), region.requiredBefore(differenceOccurrenceId));
		assertEquals(Set.of(differenceOccurrenceId), region.requiredBefore(afterOccurrenceId));

		JoinTree beforeFactor = JoinTree.factor(beforeOccurrenceId);
		JoinTree differenceFactor = JoinTree.factor(differenceOccurrenceId);
		JoinTree afterFactor = JoinTree.factor(afterOccurrenceId);
		assertTrue(region.isLegal(JoinTree.join(JoinTree.join(beforeFactor, differenceFactor), afterFactor)));
		assertTrue(region.isLegal(JoinTree.join(beforeFactor, JoinTree.join(differenceFactor, afterFactor))));
		assertFalse(region.isLegal(JoinTree.join(differenceFactor, JoinTree.join(beforeFactor, afterFactor))));
		assertFalse(region.isLegal(JoinTree.join(beforeFactor, JoinTree.join(afterFactor, differenceFactor))));

		MemoExpr differenceExpression = memo.group(differenceGroupId)
				.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.filter(expression -> expression.tupleExpr() instanceof Difference)
				.findFirst()
				.orElseThrow();
		assertEquals(2, differenceExpression.inputGroupIds().size(),
				"The ordered opaque factor must retain independently optimizable memo children");
	}

	@Test
	void retainsNonScopeChangingFilterAsTransparentRegionFactor() throws ReflectiveOperationException {
		StatementPattern filtered = pattern("urn:test:a");
		Filter filter = new Filter(filtered, new Bound(new Var("s")));
		StatementPattern right = pattern("urn:test:b");
		Join root = new Join(filter, right);
		Memo memo = memo();
		int rootGroupId = memo.intern(root);
		int filteredPatternGroupId = memo.intern(filtered);
		int filterGroupId = memo.intern(filter);
		int rightGroupId = memo.intern(right);

		Object extraction = extract(memo, rootGroupId, memo.group(rootGroupId).expressions().getFirst());

		assertTrue((boolean) invoke(extraction, "supported"));
		JoinRegion region = (JoinRegion) invoke(extraction, "region");
		assertEquals(Set.of(filterGroupId, rightGroupId),
				region.factors().stream().map(JoinFactor::groupId).collect(Collectors.toUnmodifiableSet()),
				"A non-scope-changing Filter must remain one factor instead of blocking its join region");
		assertEquals(Set.of(filterGroupId, rightGroupId), invoke(extraction, "leafGroupIds"));
		assertEquals(Set.of(rootGroupId), invoke(extraction, "expandedGroupIds"),
				"The extractor must not flatten through the Filter factor");

		MemoExpr filterExpression = memo.group(filterGroupId)
				.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.filter(expression -> expression.tupleExpr() instanceof Filter)
				.findFirst()
				.orElseThrow();
		assertEquals(List.of(filteredPatternGroupId), filterExpression.inputGroupIds(),
				"A factor opaque to join flattening must still expose its independently optimizable memo child");
		assertFalse(filterExpression.inputs().getFirst().semanticBarrier());
		assertTrue(memo.parentExpressions(filteredPatternGroupId)
				.stream()
				.anyMatch(parent -> parent.id() == filterExpression.id()));
	}

	@Test
	void nestedRepeatableFilterOverJoinBecomesMobileRegionPredicate() {
		StatementPattern code = pattern("med", "urn:test:code", "code");
		StatementPattern type = pattern("med", "urn:test:type", "type");
		StatementPattern antiFiltered = pattern("med", "urn:test:retained", "retained");
		Filter existsFiltered = new Filter(new Join(code, type),
				new Exists(pattern("patient", "urn:test:has-medication", "med")));
		Join root = new Join(existsFiltered, antiFiltered);
		Memo memo = memo();
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();
		int filterGroupId = rootExpression.inputs().getFirst().groupId();
		MemoExpr filterExpression = memo.group(filterGroupId).expressions().getFirst();
		int filterArgumentGroupId = filterExpression.inputs()
				.stream()
				.filter(input -> input.role() == MemoInput.Role.ARGUMENT)
				.mapToInt(MemoInput::groupId)
				.findFirst()
				.orElseThrow();

		MemoJoinRegionExtractor.Result extraction = MemoJoinRegionExtractor.extract(memo, rootGroupId,
				rootExpression);

		assertTrue(extraction.supported(), extraction.boundaries()::toString);
		assertEquals(3, extraction.region().factors().size(),
				"The parent region must see both filtered join inputs and the later sibling");
		assertEquals(1, extraction.region().predicates().size(),
				"The repeatable EXISTS condition must remain a costed predicate, not an atomic factor");
		assertEquals(Set.of("med"), extraction.region().predicates().getFirst().requiredBindingNames());
		assertFalse(extraction.leafGroupIds().contains(filterGroupId));
		assertTrue(extraction.expandedGroupIds().containsAll(Set.of(filterGroupId, filterArgumentGroupId)),
				"Changes below the transparent filter must reactivate the enclosing region");
	}

