	@Test
	void coreExtractorCarriesCorrelatedExtensionRequiredInputAndDependency()
			throws ReflectiveOperationException {
		StatementPattern extensionInput = pattern("row", "urn:test:row", "value");
		Extension extension = new Extension(extensionInput,
				new ExtensionElem(new Str(new Var("seed")), "derived"));
		StatementPattern producer = pattern("seed", "urn:test:seed", "seedValue");
		Join root = new Join(extension, producer);
		Memo memo = memo();
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();
		int extensionGroupId = rootExpression.inputs().getFirst().groupId();
		int producerGroupId = rootExpression.inputs().get(1).groupId();

		MemoJoinRegionExtractor.Result extraction = MemoJoinRegionExtractor.extract(memo, rootGroupId,
				rootExpression, correlatedExtensionPolicy());

		assertTrue(extraction.supported(), extraction.boundaries()::toString);
		JoinRegion region = extraction.region();
		assertEquals(2, region.factors().size(), "The Extension must remain one atomic join factor");
		int extensionOccurrenceId = occurrenceId(region, extensionGroupId);
		int producerOccurrenceId = occurrenceId(region, producerGroupId);
		assertTrue(region.requiredBefore(extensionOccurrenceId).isEmpty(),
				"A binding supplier is not an unconditional scope/order predecessor");
		assertEquals(1, region.dependencies().size());
		JoinDependency dependency = region.dependencies().getFirst();
		assertEquals(extensionOccurrenceId, dependency.dependentOccurrenceId());
		assertTrue(dependency.requiredOccurrenceIds().isEmpty());
		assertEquals(memo.universe().maskOf(Set.of("seed")), invoke(dependency, "requiredInputBindings"),
				"The dependency must retain the query-local required-input mask");
		assertEquals(1, dependency.producerClauses().size());
		ProducerClause clause = dependency.producerClauses().getFirst();
		assertEquals(memo.universe().maskOf(Set.of("seed")), clause.requiredBindings());
		int producerOrdinal = region.factors().indexOf(region.factor(producerOccurrenceId));
		assertEquals(List.of(new ProducerState(JoinSubset.ofOrdinals(producerOrdinal))), clause.alternatives());
		JoinTree extensionFirst = JoinTree.join(JoinTree.factor(extensionOccurrenceId),
				JoinTree.factor(producerOccurrenceId));
		assertFalse(region.isLegal(extensionFirst), "Without an outer binding the producer must run first");
		assertTrue(region.isLegal(extensionFirst, memo.universe().maskOf(Set.of("seed"))),
				"An already-bound input must satisfy the clause without forcing the sibling producer first");
		MemoExpr extensionExpression = memo.group(extensionGroupId)
				.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.filter(expression -> expression.tupleExpr() instanceof Extension)
				.findFirst()
				.orElseThrow();
		assertEquals(1, extensionExpression.inputGroupIds().size(),
				"An opaque Extension must retain its independently optimizable child");
	}

	@Test
	void coreExtractorTreatsExternalOnlyExtensionReferenceAsOptionalContext() {
		Extension extension = new Extension(pattern("row", "urn:test:row", "value"),
				new ExtensionElem(new Str(new Var("seed")), "derived"));
		StatementPattern sibling = pattern("other", "urn:test:other", "otherValue");
		Join root = new Join(extension, sibling);
		Memo memo = memo();
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();
		int extensionGroupId = rootExpression.inputs().getFirst().groupId();
		int siblingGroupId = rootExpression.inputs().get(1).groupId();

		MemoJoinRegionExtractor.Result extraction = MemoJoinRegionExtractor.extract(memo, rootGroupId,
				rootExpression, correlatedExtensionPolicy());

		assertTrue(extraction.supported(), extraction.boundaries()::toString);
		JoinRegion region = extraction.region();
		int extensionOccurrenceId = occurrenceId(region, extensionGroupId);
		int siblingOccurrenceId = occurrenceId(region, siblingGroupId);
		assertTrue(region.dependencies().isEmpty(),
				"An external-only scalar reference is not a hard join-region dependency");
		assertTrue(region.requiredInputBindings(extensionOccurrenceId).isEmpty(),
				"A legal unbound Extension input must not become RequiredOuterInputs");
		assertTrue(region.isLegal(JoinTree.join(JoinTree.factor(extensionOccurrenceId),
				JoinTree.factor(siblingOccurrenceId))));
		assertTrue(region.isLegal(JoinTree.join(JoinTree.factor(siblingOccurrenceId),
				JoinTree.factor(extensionOccurrenceId))));
		assertTrue(region.isLegal(JoinTree.join(JoinTree.factor(extensionOccurrenceId),
				JoinTree.factor(siblingOccurrenceId)), memo.universe().maskOf(Set.of("seed"))),
				"The same region must remain legal when the external context binds the scalar input");
	}

